app.get('/products', async (req, res) => {
  const products = await db.products.findMany();
  for (const product of products) {
    product.category = await db.categories.findById(product.categoryId);
    product.reviews = await db.reviews.findMany({ where: { productId: product.id } });
    product.averageRating = product.reviews.reduce((sum, r) => sum + r.rating, 0) / product.reviews.length;
    product.seller = await db.users.findById(product.sellerId);
  }
  res.json(products);
});

