function findDuplicateEmails(users) {
  const duplicates = [];
  for (let i = 0; i < users.length; i++) {
    for (let j = i + 1; j < users.length; j++) {
      if (users[i].email.toLowerCase() === users[j].email.toLowerCase()) {
        if (!duplicates.includes(users[i].email.toLowerCase())) {
          duplicates.push(users[i].email.toLowerCase());
        }
      }
    }
  }
  return duplicates;
}
